public class StringExample {
  public static void main(String[] args) {
    String text = "Salam, dünya!";
    String upperText = text.toUpperCase();
    String message = text + " Necəsən?";
    System.out.println("Orijinal: " + text);
    System.out.println("Böyük hərflə: " + upperText);
    System.out.println("Birləşdirilmiş: " + message);
  }
}
// Çıxış:
// Orijinal: Salam, dünya!
// Böyük hərflə: SALAM, DÜNYA!
// Birləşdirilmiş: Salam, dünya! Necəsən?

public class StringMethods {
  public static void main(String[] args) {
    String text = "Salam, dünya!";
    int length = text.length();
    String subText = text.substring(0, 5);
    boolean containsWorld = text.contains("dünya");
    String replacedText = text.replace("dünya", "Java");
    System.out.println("Uzunluq: " + length);
    System.out.println("Hissə: " + subText);
    System.out.println("Dünya var? " + containsWorld);
    System.out.println("Dəyişdirilmiş: " + replacedText);
  }
}
// Çıxış:
// Uzunluq: 13
// Hissə: Salam
// Dünya var? true
// Dəyişdirilmiş: Salam, Java!

public class StringBuilderExample {
  public static void main(String[] args) {
    StringBuilder builder = new StringBuilder("Salam");
    builder.append(", dünya!");
    builder.insert(5, " gözəl");
    String result = builder.toString();
    System.out.println("Nəticə: " + result);
  }
}
// Çıxış: Nəticə: Salam gözəl, dünya!

