public class StringExample {
  public static void main(String[] args) {
    String text = "Привет, мир!";
    String upperText = text.toUpperCase();
    String message = text + " Как дела?";
    System.out.println("Оригинал: " + text);
    System.out.println("Верхний регистр: " + upperText);
    System.out.println("Конкатенация: " + message);
  }
}
// Вывод:
// Оригинал: Привет, мир!
// Верхний регистр: ПРИВЕТ, МИР!
// Конкатенация: Привет, мир! Как дела?

public class StringMethods {
  public static void main(String[] args) {
    String text = "Привет, мир!";
    int length = text.length();
    String subText = text.substring(0, 6);
    boolean containsWorld = text.contains("мир");
    String replacedText = text.replace("мир", "Java");
    System.out.println("Длина: " + length);
    System.out.println("Подстрока: " + subText);
    System.out.println("Содержит мир? " + containsWorld);
    System.out.println("Замена: " + replacedText);
  }
}
// Вывод:
// Длина: 12
// Подстрока: Привет
// Содержит мир? true
// Замена: Привет, Java!

